let API=(()=>{var t;return window.FILA_API_URL?window.FILA_API_URL.replace(/\/$/,""):"localhost"===(t=window.location.hostname)||"127.0.0.1"===t?"http://localhost:3000":"file:"===window.location.protocol?"https://fila-treinamento.onrender.com":window.location.origin})();function escapeHTML(t){return String(t??"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#039;")}async function requestJSON(a){a=await fetch(""+API+a);if(a.ok)return a.json();{let e="Erro ao carregar histórico.";try{var t=await a.json();e=t.erro||t.error||e}catch(t){e=await a.text()||e}throw new Error(e)}}function formatarData(t){return!t||(t=new Date(t),Number.isNaN(t.getTime()))?"-":t.toLocaleString("pt-BR",{day:"2-digit",month:"2-digit",year:"numeric",hour:"2-digit",minute:"2-digit"})}function formatarDuracao(t,e){var a;return!t||!e||(e=new Date(e)-new Date(t),Number.isNaN(e))||e<0?"-":(t=Math.floor(e/1e3),e=Math.floor(t/60),0<(a=Math.floor(e/60))?a+`h ${e%60}m`:e+`m ${t%60}s`)}function limparFiltro(){document.getElementById("dataInicio").value="",document.getElementById("dataFim").value="",carregarHistorico()}function setTexto(t,e){t=document.getElementById(t);t&&(t.innerText=e)}function renderTreinamentos(t){return t.length?t.map(t=>`
        <tr>
          <td>${escapeHTML(t.pessoa||"-")}</td>
          <td>${escapeHTML(t.cliente||"-")}</td>
          <td>${escapeHTML(t.tipo||"-")}</td>
          <td>${formatarData(t.data_inicio)}</td>
          <td>${formatarDuracao(t.data_inicio,t.data_fim)}</td>
        </tr>
      `).join(""):'<tr><td colspan="5" class="empty-cell">Nenhum treinamento encontrado.</td></tr>'}function renderPuladas(t){return t.length?t.map(t=>`
        <tr>
          <td>${escapeHTML(t.pessoa||"-")}</td>
          <td>${escapeHTML(t.motivo||"-")}</td>
          <td>${formatarData(t.data_inicio)}</td>
        </tr>
      `).join(""):'<tr><td colspan="3" class="empty-cell">Nenhuma chamada pulada encontrada.</td></tr>'}function renderManutencao(t){return t.length?t.map(t=>`
        <tr>
          <td>${escapeHTML(t.pessoa||"-")}</td>
          <td>${escapeHTML(t.equipamento||"-")}</td>
          <td>${formatarData(t.data)}</td>
        </tr>
      `).join(""):'<tr><td colspan="3" class="empty-cell">Nenhuma manutenção encontrada.</td></tr>'}async function carregarHistorico(){var t=document.getElementById("dataInicio")?.value||"",e=document.getElementById("dataFim")?.value||"";let a="/historico/completo";t&&e&&(a+=`?inicio=${t}&fim=`+e);try{var n=await requestJSON(a),r=n.treinamentos||[],o=n.puladas||[],c=n.manutencao||[],i=n.ranking||[];document.getElementById("tbTreinamentos").innerHTML=renderTreinamentos(r),document.getElementById("tbPuladas").innerHTML=renderPuladas(o),document.getElementById("tbManutencao").innerHTML=renderManutencao(c),setTexto("totalTreinamentos",r.length),setTexto("totalPuladas",o.length),setTexto("totalManutencao",c.length),setTexto("totalRanking",i.length)}catch(t){console.error(t),document.getElementById("tbTreinamentos").innerHTML=`<tr><td colspan="5" class="empty-cell">${escapeHTML(t.message)}</td></tr>`}}function baixarCSV(t){var a=document.getElementById({treinamentos:"tbTreinamentos",puladas:"tbPuladas",manutencao:"tbManutencao"}[t]);if(a){let e=[];a.querySelectorAll("tr").forEach(t=>{var t=t.querySelectorAll("td");t.length&&(t=[...t].map(t=>`"${t.innerText.replaceAll('"','""')}"`).join(";"),e.push(t))});var a=new Blob([e.join("\n")],{type:"text/csv;charset=utf-8;"}),n=document.createElement("a");n.href=URL.createObjectURL(a),n.download=t+".csv",n.click(),URL.revokeObjectURL(n.href)}}carregarHistorico();